mapper.select:
select id, code, type, name
from train
where id = #{ticketId}

select *
from train


        and name like concat('%', #{name}, '%')


        and type = #{type}


        and status = #{status}


order by created_time desc

mapper.update:
update train
name = #{name}, code = #{code}, type = #{type}, status = #{status}, first_class_carriages_num = #{firstClassCarriagesNum}, first_class_carriages_list_num = #{firstClassCarriagesListNum}, second_class_carriages_num = #{secondClassCarriagesNum}, second_class_carriages_list_num = #{secondClassCarriagesListNum}, updated_time = now(), updated_by = #{updateBy}
where id = #{id}
